/**
 * Unit tests for instructions-loaded-dispatcher.ts
 * Main dispatcher: validates input, pre-reads content, wires 6 handlers, merges additionalContext
 */

import { describe, test, expect, vi, beforeEach } from 'vitest';
import type { HookInput } from '../../types.js';

// Mock all 6 handlers so dispatcher logic is tested in isolation
const mockTokenBudget = vi.fn();
const mockPriorityMap = vi.fn();
const mockDriftDetection = vi.fn();
const mockContentDedup = vi.fn();
const mockRuleConflicts = vi.fn();
const mockSmartSuggestions = vi.fn();

vi.mock('node:fs', () => ({
  readFileSync: (p: string) => `content of ${p}`,
}));

vi.mock('../../instructions-loaded/token-budget-tracker.js', () => ({
  tokenBudgetTracker: (...args: unknown[]) => mockTokenBudget(...args),
}));
vi.mock('../../instructions-loaded/priority-map.js', () => ({
  priorityMap: (...args: unknown[]) => mockPriorityMap(...args),
}));
vi.mock('../../instructions-loaded/drift-detection.js', () => ({
  driftDetection: (...args: unknown[]) => mockDriftDetection(...args),
}));
vi.mock('../../instructions-loaded/content-dedup.js', () => ({
  contentDedupScanner: (...args: unknown[]) => mockContentDedup(...args),
}));
vi.mock('../../instructions-loaded/rule-conflicts.js', () => ({
  ruleConflictDetector: (...args: unknown[]) => mockRuleConflicts(...args),
}));
vi.mock('../../instructions-loaded/smart-suggestions.js', () => ({
  smartRuleSuggestions: (...args: unknown[]) => mockSmartSuggestions(...args),
}));

vi.mock('../../lib/common.js', () => ({
  logHook: vi.fn(),
  outputSilentSuccess: () => ({ continue: true, suppressOutput: true }),
  outputPromptContext: (ctx: string) =>
    ctx?.trim()
      ? { continue: true, suppressOutput: true, hookSpecificOutput: { hookEventName: 'UserPromptSubmit', additionalContext: ctx } }
      : { continue: true, suppressOutput: true },
}));

import { instructionsLoadedDispatcher } from '../../instructions-loaded/instructions-loaded-dispatcher.js';

function makeInput(filesLoaded?: unknown): HookInput {
  return {
    tool_name: '',
    session_id: 'test-session',
    project_dir: '/test/project',
    tool_input: {},
    ...(filesLoaded !== undefined ? { files_loaded: filesLoaded } : {}),
  } as unknown as HookInput;
}

beforeEach(() => {
  vi.clearAllMocks();
  // Default: all handlers return null (silent)
  mockTokenBudget.mockReturnValue(null);
  mockPriorityMap.mockReturnValue(null);
  mockDriftDetection.mockReturnValue(null);
  mockContentDedup.mockReturnValue(null);
  mockRuleConflicts.mockReturnValue(null);
  mockSmartSuggestions.mockReturnValue(null);
});

describe('instructionsLoadedDispatcher', () => {
  describe('early exit — no files', () => {
    test('returns silent success when files_loaded is absent', () => {
      const result = instructionsLoadedDispatcher(makeInput(undefined));
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
    });

    test('returns silent success when files_loaded is an empty array', () => {
      const result = instructionsLoadedDispatcher(makeInput([]));
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
    });

    test('returns silent success when files_loaded is not an array', () => {
      const result = instructionsLoadedDispatcher(makeInput('not-an-array'));
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
    });

    test('filters out invalid elements from files_loaded', () => {
      const result = instructionsLoadedDispatcher(makeInput([null, undefined, 123, 'string']));
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
      // No valid LoadedFile elements -> no handlers called
      expect(mockTokenBudget).not.toHaveBeenCalled();
    });

    test('does not invoke any handler when files_loaded is empty', () => {
      instructionsLoadedDispatcher(makeInput([]));
      expect(mockTokenBudget).not.toHaveBeenCalled();
      expect(mockPriorityMap).not.toHaveBeenCalled();
    });
  });

  describe('all handlers silent', () => {
    test('returns silent success when all 6 handlers return null', () => {
      const input = makeInput([{ path: '/project/CLAUDE.md', byte_size: 1000 }]);
      const result = instructionsLoadedDispatcher(input);
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
    });

    test('calls all 6 handlers exactly once', () => {
      const input = makeInput([{ path: '/project/CLAUDE.md', byte_size: 500 }]);
      instructionsLoadedDispatcher(input);
      expect(mockTokenBudget).toHaveBeenCalledOnce();
      expect(mockPriorityMap).toHaveBeenCalledOnce();
      expect(mockDriftDetection).toHaveBeenCalledOnce();
      expect(mockContentDedup).toHaveBeenCalledOnce();
      expect(mockRuleConflicts).toHaveBeenCalledOnce();
      expect(mockSmartSuggestions).toHaveBeenCalledOnce();
    });

    test('passes files and content cache to each handler', () => {
      const files = [
        { path: '/project/CLAUDE.md', byte_size: 1000 },
        { path: '/project/.claude/rules/a.md', byte_size: 500 },
      ];
      instructionsLoadedDispatcher(makeInput(files));
      // First arg is files, second is Map<string, string>
      expect(mockTokenBudget).toHaveBeenCalledWith(files, expect.any(Map));
      expect(mockDriftDetection).toHaveBeenCalledWith(files, expect.any(Map));
      // Verify the map has pre-read content
      const passedMap = mockTokenBudget.mock.calls[0][1] as Map<string, string>;
      expect(passedMap.size).toBe(2);
      expect(passedMap.get('/project/CLAUDE.md')).toBe('content of /project/CLAUDE.md');
    });
  });

  describe('handler output merging', () => {
    test('returns prompt context with additionalContext when one handler produces output', () => {
      mockTokenBudget.mockReturnValue('[Instruction Budget] 5000 tokens');
      const input = makeInput([{ path: '/project/CLAUDE.md', byte_size: 20_000 }]);
      const result = instructionsLoadedDispatcher(input);
      expect(result.continue).toBe(true);
      expect(result.hookSpecificOutput?.additionalContext).toBe('[Instruction Budget] 5000 tokens');
    });

    test('joins multiple handler outputs with double newline', () => {
      mockTokenBudget.mockReturnValue('Budget output');
      mockPriorityMap.mockReturnValue('Priority output');
      const input = makeInput([{ path: '/project/CLAUDE.md', byte_size: 20_000 }]);
      const result = instructionsLoadedDispatcher(input);
      const context = result.hookSpecificOutput?.additionalContext;
      expect(context).toContain('Budget output');
      expect(context).toContain('Priority output');
      expect(context).toContain('\n\n');
    });

    test('includes only non-null handler results', () => {
      mockTokenBudget.mockReturnValue('Budget output');
      // All others null
      const input = makeInput([{ path: '/project/CLAUDE.md', byte_size: 20_000 }]);
      const result = instructionsLoadedDispatcher(input);
      const context = result.hookSpecificOutput?.additionalContext;
      expect(context).toBe('Budget output');
    });
  });

  describe('handler error isolation', () => {
    test('continues running remaining handlers when one throws', () => {
      mockTokenBudget.mockImplementation(() => { throw new Error('budget exploded'); });
      mockSmartSuggestions.mockReturnValue('Smart suggestion output');

      const input = makeInput([{ path: '/project/CLAUDE.md', byte_size: 1000 }]);
      const result = instructionsLoadedDispatcher(input);

      expect(result.continue).toBe(true);
      const context = result.hookSpecificOutput?.additionalContext;
      expect(context).toContain('Smart suggestion output');
    });

    test('returns silent success when all handlers throw', () => {
      const boom = () => { throw new Error('boom'); };
      mockTokenBudget.mockImplementation(boom);
      mockPriorityMap.mockImplementation(boom);
      mockDriftDetection.mockImplementation(boom);
      mockContentDedup.mockImplementation(boom);
      mockRuleConflicts.mockImplementation(boom);
      mockSmartSuggestions.mockImplementation(boom);

      const input = makeInput([{ path: '/project/CLAUDE.md', byte_size: 1000 }]);
      expect(() => instructionsLoadedDispatcher(input)).not.toThrow();
      const result = instructionsLoadedDispatcher(input);
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
    });
  });
});
